use hotaru_http::util::form::UrlEncodedForm;

// As emitted by Chrome / Firefox / Safari for a single-field <form method="POST">
// where the user typed "Hello world":
let form = UrlEncodedForm::parse(b"greeting=Hello+world".to_vec());
assert_eq!(form.get("greeting").map(String::as_str), Some("Hello world"));
// Pre-fix: returned Some("Hello+world") — the space is permanently lost.

// Query string round-trip:
//   GET /search?q=Hello+world
//   req.query("q") pre-fix → Some("Hello+world")
//   req.query("q") post-fix → Some("Hello world")
